## Error Handling Middleware
```typescript
const errorHandler: Middleware = async (ctx, next) => {
  try {
    await next();
  } catch (error) {
    ctx.status = error.statusCode || 500;
    return {
      error: {
        code: error.code || 'INTERNAL_ERROR',
        message: error.message,
      },
    };
  }
};

app.use(errorHandler);
```

