## Transactions
Use transactions for atomic operations:

```typescript
import { db } from '@nova/orm';

await db.transaction(async (trx) => {
  const user = await trx('users').insert({ name: 'Alice', email: 'alice@example.com' });
  await trx('wallets').insert({ userId: user.id, balance: 0 });
  await trx('audit_log').insert({ action: 'user_created', userId: user.id });
});
```

## Unit Tests
Create test files alongside your source files with the `.test.ts` extension:

```typescript
// src/services/user.service.test.ts
import { describe, it, expect } from '@nova/test';
import { UserService } from './user.service';

describe('UserService', () => {
  it('should create a user', async () => {
    const user = await UserService.create({
      name: 'Alice',
      email: 'alice@example.com',
    });

    expect(user.id).toBeDefined();
    expect(user.name).toBe('Alice');
    expect(user.email).toBe('alice@example.com');
  });

  it('should throw on duplicate email', async () => {
    await UserService.create({ name: 'Alice', email: 'alice@example.com' });

    await expect(
      UserService.create({ name: 'Bob', email: 'alice@example.com' })
    ).rejects.toThrow('Email already exists');
  });
});
```

